// Serial Ports
package portdispatcher

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40410/idl"
	"github.com/arminguenther/xeruspower-go/v40410/serial/serialport"
)

// Top-level interface of the serial port manager
type PortDispatcher interface {
	idl.Object

	// Get serial ports
	//
	// Returns a map of serial ports that are both
	//   - available on the device
	//   - monitored by the system
	//
	// The mapping is 'symbolic port name' -> 'port instance'.
	//
	//	@return -- A map with available port instances
	GetPorts(ctx context.Context) (map[string]serialport.SerialPort, error)
}
